\]

\[
\lim_{N \to \infty} \left( \frac{N^2}{2(1 - i)} - \frac{N}{2(1 - i)} + \frac{iN}{2(1 - i)} \right) = \lim_{N \to \infty} \left( \frac{N^2}{2(1 - i)} - \frac{N(1 - i)}{2(1 - i)^2} \right) = \lim_{N \to \infty} \left( \frac{N^2}{2(1 - i)} - \frac{N}{2(1 - i)} + \frac{iN}{2(1 - i)} \right) = \lim_{N \to \infty} \frac{N(N - 1 + i)}{2(1 - i)}
