\[
\lim_{N \to \infty} \frac{N(N - 1 + i)}{2(1 - i)} = \lim_{N \to \infty} \frac{N^2 - N + iN}{2(1 - i)} = \lim_{N \to \infty} \frac{N^2}{2(1 - i)} - \frac{N}{2(1 - i)} + \frac{iN}{2(1 - i)} = \lim_{N \to \infty} \frac{N^2}{2(1 - i)} - \frac{N(1 - i)}{2(1 - i)^2} = \lim_{N \to \infty} \frac{N^2}{2(1 - i)} - \frac{N}{2(1 - i)} + \frac{iN}{2(1 - i)} = \lim_{N \to \infty} \frac{N(N - 1 + i)}{2(1 - i)} = \lim_{N \to \infty} \frac{N(N - 1)}{2(1 - i)} + \lim_{N \to \infty} \frac{iN}{2(1 - i)} = \infty + \lim_{N \to \infty} \frac{iN}{2(1 - i)}
